    if n < 3 {
        return false
    }

    // Find the peak point p
    p := 1
    for p < n-1 && nums[p] > nums[p-1] {
        p++
    }

    // Check if p is valid (must be between 1 and n-2)
    if p == 0 || p == n-1 {
        return false
