    // Find the valley point q
    q := p
    for q < n-1 && nums[q] > nums[q+1] {
        q++
    }

    // Check if q is valid (must be between p and n-2)
    if q == p || q == n-1 {
        return false
    }

    // Check if the first part is strictly increasing
    for i := 0; i < p; i++ {
        if nums[i] >= nums[i+1] {
            return false
        }
    }

    // Check if the middle part is strictly decreasing
